import{_ as a,o,c as t,ag as n}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Daily Papers - 2026-04-09 (Issue #1)","description":"","frontmatter":{"title":"Daily Papers - 2026-04-09 (Issue #1)","date":"2026-04-09T00:00:00.000Z","tags":["daily-papers","paper-notes"]},"headers":[],"relativePath":"posts/paper-notes/2026-04-09-issue-1.md","filePath":"posts/paper-notes/2026-04-09-issue-1.md","lastUpdated":1775751506000}'),r={name:"posts/paper-notes/2026-04-09-issue-1.md"};function i(s,e,l,c,u,p){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="daily-papers-2026-04-09-issue-1" tabindex="-1">Daily Papers - 2026-04-09 (Issue #1) <a class="header-anchor" href="#daily-papers-2026-04-09-issue-1" aria-label="Permalink to &quot;Daily Papers - 2026-04-09 (Issue #1)&quot;">​</a></h1><blockquote><p>Today&#39;s paper collection. Add papers throughout the day. Close this issue when full.</p></blockquote><hr><h2 id="paper-1-josephson-current-and-noise-at-a-superconductor-quantum-spin-hall-insulator-superconductor-junction" tabindex="-1">Paper #1: Josephson Current and Noise at a Superconductor-Quantum Spin Hall Insulator-Superconductor Junction <a class="header-anchor" href="#paper-1-josephson-current-and-noise-at-a-superconductor-quantum-spin-hall-insulator-superconductor-junction" aria-label="Permalink to &quot;Paper #1: Josephson Current and Noise at a Superconductor-Quantum Spin Hall Insulator-Superconductor Junction&quot;">​</a></h2><p><strong>Authors</strong>: Liang Fu, C.L. Kane<br><strong>arXiv</strong>: <a href="https://arxiv.org/abs/0804.4469" target="_blank" rel="noreferrer">0804.4469</a><br><strong>Key words</strong>: quantum spin hall, majorana, josephson, superconductivity, topology, proximity<br><strong>Year</strong>: 2008</p><h3 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Seminal work exploring the interplay between topological quantum spin Hall insulators and superconductivity. The paper theoretically investigates Josephson junctions formed by superconductors on either side of a 2D topological insulator.</p><h3 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h3><ul><li><strong>Quantum Spin Hall Insulator</strong>: 2D topological phase with helical edge states</li><li><strong>Proximity Effect</strong>: Inducing superconductivity in the edge states via coupling to s-wave superconductors</li><li><strong>Majorana Fermions</strong>: Predicted emergence of Majorana bound states at the junction</li><li><strong>Fractional Josephson Effect</strong>: 4π-periodic Josephson current as signature of Majorana modes</li></ul><h3 id="key-innovations" tabindex="-1">Key Innovations <a class="header-anchor" href="#key-innovations" aria-label="Permalink to &quot;Key Innovations&quot;">​</a></h3><ol><li><strong>Theoretical Framework</strong>: Systematic analysis of superconductor-topological insulator-superconductor (S-TI-S) junctions</li><li><strong>Majorana Signature</strong>: Prediction that zero-energy Majorana bound states manifest as fractional AC Josephson effect</li><li><strong>Noise Characteristics</strong>: Calculation of noise spectrum to distinguish Majorana modes from conventional Andreev bound states</li><li><strong>Experimental Predictions</strong>: Concrete signatures for experimental detection of Majorana fermions in solid-state systems</li></ol><h3 id="technical-approach" tabindex="-1">Technical Approach <a class="header-anchor" href="#technical-approach" aria-label="Permalink to &quot;Technical Approach&quot;">​</a></h3><ul><li>Bogoliubov-de Gennes (BdG) Hamiltonian for the junction</li><li>Green&#39;s function methods for calculating current and noise</li><li>Low-energy effective theory for the edge states</li></ul><h3 id="reading-notes" tabindex="-1">Reading Notes <a class="header-anchor" href="#reading-notes" aria-label="Permalink to &quot;Reading Notes&quot;">​</a></h3><p>(To be filled after careful reading)</p><ul><li>[ ] Master the BdG Hamiltonian construction</li><li>[ ] Understand the fractional Josephson effect derivation</li><li>[ ] Study the noise calculation methodology</li><li>[ ] Connect to subsequent experimental works</li></ul><hr><h2 id="paper-2-ferbo-a-superconducting-circuit-with-andreev-relaxation-protection" tabindex="-1">Paper #2: FerBo: A superconducting circuit with Andreev relaxation protection <a class="header-anchor" href="#paper-2-ferbo-a-superconducting-circuit-with-andreev-relaxation-protection" aria-label="Permalink to &quot;Paper #2: FerBo: A superconducting circuit with Andreev relaxation protection&quot;">​</a></h2><p><strong>Authors</strong>: J. J. Caceres, D. Sanz Marco, J. Ortuzar, P. P. Ortiz, S. Dusuel, I. Safi, E. S. Timm, J. E. Mooij, C. Urbina, A. L. Yeyati, M. April, A. Levy Yeyati, D. Estève, M. Devoret, H. Pothier<br><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2604.01145" target="_blank" rel="noreferrer">2604.01145</a><br><strong>Key words</strong>: superconducting qubit, Andreev levels, josephson junction, dephasing protection, relaxation protection<br><strong>Year</strong>: 2026</p><h3 id="summary-1" tabindex="-1">Summary <a class="header-anchor" href="#summary-1" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>A novel superconducting quantum circuit (FerBo) combining a large inductance, small capacitor, and well-transmitting Josephson weak link. Protection against relaxation arises from hybridization between fermionic Andreev levels and bosonic electromagnetic mode of the LC circuit.</p><h3 id="core-concepts-1" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts-1" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h3><ul><li><strong>Andreev Levels</strong>: Bound states in Josephson weak link with fermionic character</li><li><strong>Fermion-Boson Hybridization</strong>: Coupling between Andreev levels and LC circuit mode</li><li><strong>Relaxation Protection</strong>: Suppressed decay due to hybridized nature of states</li><li><strong>Dephasing Protection</strong>: Phase-space delocalization as in fluxonium qubit</li></ul><h3 id="key-innovations-1" tabindex="-1">Key Innovations <a class="header-anchor" href="#key-innovations-1" aria-label="Permalink to &quot;Key Innovations&quot;">​</a></h3><ol><li><strong>FerBo Architecture</strong>: Parallel arrangement of L, C, and Josephson weak link</li><li><strong>Andreev Protection</strong>: First proposal for relaxation protection via Andreev level hybridization</li><li><strong>Wide Parameter Range</strong>: Robustness over experimentally accessible parameters</li><li><strong>Dual Protection</strong>: Both relaxation and dephasing protection in single circuit</li></ol><h3 id="technical-approach-1" tabindex="-1">Technical Approach <a class="header-anchor" href="#technical-approach-1" aria-label="Permalink to &quot;Technical Approach&quot;">​</a></h3><ul><li>Circuit quantization with parallel L-C-Josephson elements</li><li>Analysis of Andreev level spectrum in transparent weak link</li><li>Numerical simulation of qubit coherence properties</li><li>Comparison with fluxonium and other protected qubits</li></ul><h3 id="reading-notes-1" tabindex="-1">Reading Notes <a class="header-anchor" href="#reading-notes-1" aria-label="Permalink to &quot;Reading Notes&quot;">​</a></h3><p>(To be filled after careful reading)</p><ul><li>[ ] Understand the FerBo circuit Hamiltonian</li><li>[ ] Study the Andreev level - LC mode hybridization mechanism</li><li>[ ] Analyze the protection mechanisms against decoherence</li><li>[ ] Compare with other protected qubit designs (fluxonium, 0-π)</li></ul><hr><p><em>Issue status: 🔴 Closed (moved to <a href="./2026-04-10-issue-1">2026-04-10 Issue #1</a>)</em></p>',32)])])}const g=a(r,[["render",i]]);export{h as __pageData,g as default};
